6169 static Value *BuildSubAggregate(Value *From, ArrayRef<unsigned> idx_range,
6170                                 BasicBlock::iterator InsertBefore) {
6171   Type *IndexedType = ExtractValueInst::getIndexedType(From->getType(),
6172                                                              idx_range);
6173   Value *To = PoisonValue::get(IndexedType);
6174   SmallVector<unsigned, 10> Idxs(idx_range);
6175   unsigned IdxSkip = Idxs.size();
6176 
6177   return BuildSubAggregate(From, To, IndexedType, Idxs, IdxSkip, InsertBefore);
